import{_ as a,c as o,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Recursos Avançados: Princípio de Formatação | opencode-md-table-formatter","description":"Entenda profundamente o princípio de formatação do opencode-md-table-formatter. Domine o modo de ocultação, especificações de tabelas e métodos de alinhamento, entenda abrangentemente como o plugin funciona.","frontmatter":{"title":"Recursos Avançados: Princípio de Formatação | opencode-md-table-formatter","subtitle":"Recursos Avançados: Princípio de Formatação | opencode-md-table-formatter","sidebarTitle":"Entenda como funciona","order":2,"description":"Entenda profundamente o princípio de formatação do opencode-md-table-formatter. Domine o modo de ocultação, especificações de tabelas e métodos de alinhamento, entenda abrangentemente como o plugin funciona.","prerequisite":["start-getting-started","start-features"],"tags":["avançado","princípio","especificações"]},"headers":[],"relativePath":"pt/franlol/opencode-md-table-formatter/advanced/index.md","filePath":"pt/franlol/opencode-md-table-formatter/advanced/index.md"}'),n={name:"pt/franlol/opencode-md-table-formatter/advanced/index.md"};function r(d,e,s,l,c,p){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="recursos-avancados-entenda-profundamente-os-detalhes-tecnicos-da-formatacao-de-tabelas-markdown" tabindex="-1">Recursos Avançados: Entenda Profundamente os Detalhes Técnicos da Formatação de Tabelas Markdown <a class="header-anchor" href="#recursos-avancados-entenda-profundamente-os-detalhes-tecnicos-da-formatacao-de-tabelas-markdown" aria-label="Permalink to &quot;Recursos Avançados: Entenda Profundamente os Detalhes Técnicos da Formatação de Tabelas Markdown&quot;">​</a></h1><h2 id="visao-geral-do-capitulo" tabindex="-1">Visão geral do capítulo <a class="header-anchor" href="#visao-geral-do-capitulo" aria-label="Permalink to &quot;Visão geral do capítulo&quot;">​</a></h2><p>Este capítulo explora profundamente os detalhes técnicos da formatação de tabelas Markdown, incluindo o princípio de funcionamento do modo de ocultação do OpenCode, as especificações de estrutura de tabelas válidas e explicações detalhadas dos métodos de alinhamento. Ao aprender este conteúdo, você entenderá abrangentemente como o plugin processa a formatação de tabelas e como evitar erros comuns.</p><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de aprendizado&quot;">​</a></h2><p>Recomenda-se aprender o conteúdo deste capítulo na seguinte ordem:</p><div class="info custom-block"><p class="custom-block-title">Caminho de aprendizado</p><ol><li><strong>Princípio do Modo de Ocultação</strong> → Entenda por que é necessário tratamento especial para o modo de ocultação do OpenCode</li><li><strong>Especificações de Tabelas</strong> → Domine que tipo de tabelas podem ser formatadas corretamente</li><li><strong>Detalhes de Alinhamento</strong> → Aprenda como controlar o alinhamento e a estética das tabelas</li></ol></div><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><p>Antes de começar este capítulo, certifique-se de que você já:</p><ul><li>[x] Concluiu <a href="./../start/getting-started/">Comece em 1 minuto</a>, instalou e configurou o plugin com sucesso</li><li>[x] Leu <a href="./../start/features/">Visão Geral de Recursos</a>, entendeu as funcionalidades básicas do plugin</li></ul><div class="warning custom-block"><p class="custom-block-title">Dica importante</p><p>Se você ainda não concluiu o aprendizado básico, recomenda-se voltar ao <a href="./../start/getting-started/">Guia de Início</a> para começar.</p></div><h2 id="navegacao-do-curso" tabindex="-1">Navegação do curso <a class="header-anchor" href="#navegacao-do-curso" aria-label="Permalink to &quot;Navegação do curso&quot;">​</a></h2><h3 id="principio-do-modo-de-ocultacao" tabindex="-1"><a href="./concealment-mode/">Princípio do Modo de Ocultação</a> <a class="header-anchor" href="#principio-do-modo-de-ocultacao" aria-label="Permalink to &quot;[Princípio do Modo de Ocultação](./concealment-mode/)&quot;">​</a></h3><p>Entenda o princípio de funcionamento do modo de ocultação do OpenCode e como o plugin calcula corretamente a largura de exibição. Você aprenderá:</p><ul><li>O que é o modo de ocultação e por que precisa de tratamento especial</li><li>Como funciona o algoritmo de remoção de símbolos Markdown</li><li>O papel do <code>Bun.stringWidth()</code> no cálculo de largura</li></ul><p><strong>Tempo estimado</strong>: 8 minutos | <strong>Dificuldade</strong>: Média | <strong>Pré-requisito</strong>: Visão Geral de Recursos</p><hr><h3 id="especificacoes-de-tabelas" tabindex="-1"><a href="./table-spec/">Especificações de Tabelas</a> <a class="header-anchor" href="#especificacoes-de-tabelas" aria-label="Permalink to &quot;[Especificações de Tabelas](./table-spec/)&quot;">​</a></h3><p>Domine os requisitos de estrutura de tabelas Markdown válidas, evitando erros de &quot;tabela inválida&quot;. Você aprenderá:</p><ul><li>Que tipo de estrutura de tabela é válida</li><li>O papel e requisitos de formato da linha separadora</li><li>Princípio de verificação de consistência do número de colunas</li><li>Como identificar rapidamente problemas de estrutura de tabela</li></ul><p><strong>Tempo estimado</strong>: 6 minutos | <strong>Dificuldade</strong>: Iniciante | <strong>Pré-requisito</strong>: Princípio do Modo de Ocultação</p><hr><h3 id="detalhes-de-alinhamento" tabindex="-1"><a href="./alignment/">Detalhes de Alinhamento</a> <a class="header-anchor" href="#detalhes-de-alinhamento" aria-label="Permalink to &quot;[Detalhes de Alinhamento](./alignment/)&quot;">​</a></h3><p>Domine a sintaxe e efeitos dos três métodos de alinhamento, tornando as tabelas mais bonitas. Você aprenderá:</p><ul><li>Sintaxe de alinhamento à esquerda, centralizado e alinhamento à direita</li><li>Como especificar o método de alinhamento na linha separadora</li><li>Algoritmo de preenchimento de conteúdo de células</li><li>Relação entre alinhamento e largura de exibição</li></ul><p><strong>Tempo estimado</strong>: 10 minutos | <strong>Dificuldade</strong>: Média | <strong>Pré-requisito</strong>: Especificações de Tabelas</p><hr><h2 id="resumo-do-capitulo" tabindex="-1">Resumo do capítulo <a class="header-anchor" href="#resumo-do-capitulo" aria-label="Permalink to &quot;Resumo do capítulo&quot;">​</a></h2><p>Após concluir este capítulo, você:</p><ul><li>✅ Entenderá o princípio de funcionamento do modo de ocultação do OpenCode</li><li>✅ Dominará os requisitos de estrutura de tabelas válidas</li><li>✅ Será capaz de identificar e corrigir tabelas inválidas</li><li>✅ Usará proficientemente os três métodos de alinhamento</li><li>✅ Entenderá os detalhes técnicos da implementação interna do plugin</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h2><p>Após concluir este capítulo, você pode:</p><ol><li><strong>Resolver problemas práticos</strong> → Aprenda <a href="./../../faq/troubleshooting/">Perguntas Frequentes</a>, localize e resolva rapidamente problemas</li><li><strong>Entender limites técnicos</strong> → Leia <a href="./../../appendix/limitations/">Limitações Conhecidas</a>, entenda os cenários de aplicação do plugin</li><li><strong>Entender profundamente a implementação</strong> → Veja <a href="./../../appendix/tech-details/">Detalhes Técnicos</a>, entenda o mecanismo de cache e otimização de desempenho</li></ol><hr><div class="tip custom-block"><p class="custom-block-title">Sugestão prática</p><p>Se você quer resolver rapidamente problemas de formatação de tabelas, pode primeiro ler <a href="./table-spec/">Especificações de Tabelas</a> deste capítulo, que contém os casos mais comuns de tabelas inválidas.</p></div>',34)])])}const h=a(n,[["render",r]]);export{u as __pageData,h as default};
